        args = CGNativeMember.getArgs(self, returnType, argList)
        if self.member.getExtendedAttribute(
            "ReflectedHTMLAttributeReturningFrozenArray"
        ):
            args.insert(0, Argument("bool*", "aUseCachedValue"))
